// frontend/src/components/Dashboard/Dashboard.js
import React, { useState } from 'react';
import {
  Container,
  Grid,
  Box,
  AppBar,
  Toolbar,
  IconButton,
  Typography,
  Menu,
  MenuItem,
  Avatar,
  Divider,
  Button,
  useTheme,
  useMediaQuery
} from '@mui/material';
import {
  AccountCircle,
  Logout,
  Refresh,
  Sync,
  Visibility,
  VisibilityOff,
  AdminPanelSettings
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { toast } from 'react-toastify';
import dashboardService from '../../services/dashboardService';

import StatsCards from './StatsCards';
import OpenPositions from './OpenPositions';
import HistoricoTrades from './HistoricoTrades';
import Profile from './Profile';

const Dashboard = () => {
  const navigate = useNavigate();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const { user, logout, setUser } = useAuth();

  const [anchorEl, setAnchorEl] = useState(null);
  const [refreshing, setRefreshing] = useState(false);
  const [hideValues, setHideValues] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const [autoSyncStatus, setAutoSyncStatus] = useState(false);
  const [autoSyncLoading, setAutoSyncLoading] = useState(false);

  const handleRefresh = async () => {
    setRefreshing(true);
    try {
      await dashboardService.syncTrades();
      toast.success('Dados atualizados!');
    } catch (error) {
      console.error('Erro ao atualizar dados:', error);
      toast.error('Erro ao atualizar dados');
    } finally {
      setRefreshing(false);
    }
  };

  const handleToggleAutoSync = async () => {
    try {
      setAutoSyncLoading(true);
      if (autoSyncStatus) {
        await dashboardService.stopAutoSync();
        toast.success('Sincronização automática desativada!');
      } else {
        await dashboardService.startAutoSync();
        toast.success('Sincronização automática ativada!');
      }
      setAutoSyncStatus(!autoSyncStatus);
    } catch (error) {
      console.error('Erro ao alterar sincronização automática:', error);
      toast.error('Erro ao alterar sincronização automática');
    } finally {
      setAutoSyncLoading(false);
    }
  };

  const handleMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleProfileOpen = () => {
    setProfileOpen(true);
    handleMenuClose();
  };

  const handleProfileClose = () => {
    setProfileOpen(false);
  };

  const handleUserUpdate = (updatedUser) => {
    setUser(updatedUser);
  };

  const handleLogout = async () => {
    try {
      setAnchorEl(null);
      await logout();
    } catch (error) {
      console.error('Erro no logout:', error);
    }
  };

  const handleGoToAdmin = () => {
    navigate('/admin');
    handleMenuClose();
  };

  const handleToggleValues = () => {
    setHideValues(!hideValues);
  };

  return (
    <Box sx={{ flexGrow: 1, minHeight: '100vh', bgcolor: 'background.default' }}>
      {/* Barra Superior */}
      <AppBar position="static" elevation={0} sx={{ bgcolor: 'background.paper', borderBottom: 1, borderColor: 'divider' }}>
        <Toolbar>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1, color: 'primary.main', fontWeight: 'bold' }}>
            Nautilus Automação
          </Typography>

          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            {user?.is_admin && (
              <Button
                startIcon={<AdminPanelSettings />}
                onClick={handleGoToAdmin}
                size="small"
                variant="contained"
                color="secondary"
                sx={{ display: { xs: 'none', md: 'flex' } }}
              >
                Admin
              </Button>
            )}

            <Button
              startIcon={<Sync />}
              onClick={handleToggleAutoSync}
              disabled={autoSyncLoading}
              size="small"
              variant={autoSyncStatus ? "contained" : "outlined"}
              color={autoSyncStatus ? "success" : "primary"}
            >
              {autoSyncStatus ? 'Auto-Sync ON' : 'Auto-Sync OFF'}
            </Button>

            <IconButton onClick={handleToggleValues} color="default" title={hideValues ? "Mostrar valores" : "Ocultar valores"}>
              {hideValues ? <VisibilityOff /> : <Visibility />}
            </IconButton>

            <IconButton onClick={handleRefresh} disabled={refreshing} color="primary">
              <Refresh />
            </IconButton>

            <IconButton size="large" onClick={handleMenuOpen} color="inherit">
              <Avatar sx={{ width: 32, height: 32, bgcolor: 'primary.main' }}>
                {user?.full_name?.charAt(0) || <AccountCircle />}
              </Avatar>
            </IconButton>
          </Box>

          <Menu
            anchorEl={anchorEl}
            open={Boolean(anchorEl)}
            onClose={handleMenuClose}
            transformOrigin={{ horizontal: 'right', vertical: 'top' }}
            anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
          >
            <MenuItem disabled>
              <Typography variant="body2" color="text.secondary">{user?.email}</Typography>
            </MenuItem>
            <Divider />
            <MenuItem onClick={handleProfileOpen}>
              <AccountCircle fontSize="small" sx={{ mr: 1 }} /> Perfil
            </MenuItem>
            <MenuItem onClick={handleLogout}>
              <Logout fontSize="small" sx={{ mr: 1 }} /> Sair
            </MenuItem>
          </Menu>
        </Toolbar>
      </AppBar>

      {/* Conteúdo Principal */}
      <Container maxWidth="xl">
        <Box sx={{ flexGrow: 1, py: 3 }}>
          <Grid container spacing={3}>
            {/* Cards de Estatísticas */}
            <Grid item xs={12}>
              <StatsCards />
            </Grid>

            {/* Posições Abertas */}
            <Grid item xs={12}>
              <OpenPositions hideValues={hideValues} />
            </Grid>

            {/* Histórico de Trades */}
            <Grid item xs={12}>
              <HistoricoTrades />
            </Grid>
          </Grid>
        </Box>
      </Container>

      {/* Modal de Perfil */}
      <Profile
        open={profileOpen}
        onClose={handleProfileClose}
        user={user}
        onUserUpdate={handleUserUpdate}
      />
    </Box>
  );
};

export default Dashboard;
